+/// Fold (X != -1) & ((X + 1) <= Y) --> X < Y
+/// Fold (X == -1) | ((X + 1) > Y)  --> X >= Y
+static Value *foldUnsignedOverflowCheck(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                        bool IsAnd,
+                                        InstCombiner::BuilderTy &Builder) {
+  // Match Cmp0: icmp ne/eq X, -1
+  ICmpInst::Predicate EqPred;
+  Value *X;
+  if (!match(Cmp0, m_ICmp(EqPred, m_Value(X), m_AllOnes())) ||
+      !ICmpInst::isEquality(EqPred))
+    return nullptr;
+
+  // For AND: (X != -1) && ((X + 1) <= Y)  -->  X < Y
+  // For OR:  (X == -1) || ((X + 1) > Y)   -->  X >= Y
+  if ((IsAnd && EqPred != ICmpInst::ICMP_NE) ||
+      (!IsAnd && EqPred != ICmpInst::ICMP_EQ))
+    return nullptr;
+
+  // Match Cmp1: icmp ule/ugt (add X, 1), Y  or  icmp uge/ult Y, (add X, 1)
+  ICmpInst::Predicate UnsignedPred;
+  Value *Add, *Y;
+  if (match(Cmp1, m_c_ICmp(UnsignedPred, m_Value(Add), m_Value(Y))) &&
+      match(Add, m_c_Add(m_Specific(X), m_One()))) {
+    // For AND: (X != -1) && ((X + 1) <= Y) --> X < Y
+    if (IsAnd && UnsignedPred == ICmpInst::ICMP_ULE)
+      return Builder.CreateICmpULT(X, Y);
+    // For OR: (X == -1) || ((X + 1) > Y) --> X >= Y
+    if (!IsAnd && UnsignedPred == ICmpInst::ICMP_UGT)
+      return Builder.CreateICmpUGE(X, Y);
+  }
+
+  return nullptr;
+}
